const items = $input.all();

return items.map((item) => {
  const msg = item.json.message || {};
  const from = msg.from || {};
  const chat = msg.chat || {};

  return {
    json: {
      telegram_user_id: from.id ? Number(from.id) : null,
      telegram_chat_id: chat.id ? Number(chat.id) : null,
      username: from.username || null,
      first_name: from.first_name || null,
      last_name: from.last_name || null,
      language_code: from.language_code || null,
      message_id: msg.message_id ? Number(msg.message_id) : null,
      message_text: msg.text || "",
      raw_profile: JSON.stringify(from || {})
    }
  };
});

const items = $input.all();
const input = $('Normalize Telegram Input').first().json;

return items.map((item) => {
  const candidate = item.json || {};

  return {
    json: {
      telegram_user_id: input.telegram_user_id,
      telegram_chat_id: input.telegram_chat_id,
      message_id: input.message_id,
      message_text: input.message_text,
      candidate,
      agent_input: [
        "Current candidate state:",
        JSON.stringify(candidate, null, 2),
        "",
        "Latest user message:",
        input.message_text
      ].join("\n")
    }
  };
});

const input = $('Normalize Telegram Input').first().json;
const build = $('Build Agent Input').first().json || {};
const currentCandidate = build.candidate || {};

function pickAgentOutput(json) {
  if (typeof json === "string") return json;
  if (json && typeof json.output === "object") return json.output;
  if (json && typeof json.output === "string") return json.output;
  if (json && typeof json.text === "string") return json.text;
  if (json && typeof json.response === "string") return json.response;
  if (json && typeof json.message === "string") return json.message;
  return json;
}

function extractJsonText(text) {
  const trimmed = String(text || "").trim();
  const fenceMatch = trimmed.match(/^\s*```(?:json)?\s*([\s\S]*?)\s*```\s*$/i);
  if (fenceMatch) return fenceMatch[1].trim();

  const firstBrace = trimmed.indexOf("{");
  const lastBrace = trimmed.lastIndexOf("}");
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    return trimmed.slice(firstBrace, lastBrace + 1);
  }

  return trimmed;
}

const rawOutput = pickAgentOutput($json);
let parsed;
let parseError = null;

try {
  parsed = typeof rawOutput === "object" && rawOutput !== null
    ? rawOutput
    : JSON.parse(extractJsonText(rawOutput));
} catch (error) {
  parseError = error.message;
  parsed = {
    reply: typeof rawOutput === "string" && rawOutput.trim()
      ? rawOutput.trim()
      : "This question needs to be confirmed with the administrator. You can ask your mentor during the trial period.",
    candidate_update: {
      country: null,
      age_passed: null,
      english_passed: null,
      has_android: null,
      internet_ok: null,
      hours_ok: null,
      us_time_ok: null,
      commission_ok: null,
      interested: null,
      screening_step: currentCandidate.screening_step || "not_started",
      screening_status: "unknown",
      rejection_reason: null
    }
  };
}

const update = parsed.candidate_update || {};

function boolToTinyInt(value) {
  if (value === true) return 1;
  if (value === false) return 0;
  return null;
}

const allowedStatuses = ["not_started", "in_progress", "passed", "rejected", "unknown"];
const allowedSteps = [
  "not_started",
  "experience",
  "country",
  "age",
  "english",
  "android",
  "internet",
  "hours",
  "us_time",
  "commission",
  "interest",
  "download_sent",
  "rejected"
];

const screeningStatus = allowedStatuses.includes(update.screening_status)
  ? update.screening_status
  : "unknown";

const screeningStep = allowedSteps.includes(update.screening_step)
  ? update.screening_step
  : (currentCandidate.screening_step || "not_started");

return [{
  json: {
    telegram_user_id: input.telegram_user_id,
    telegram_chat_id: input.telegram_chat_id,
    message_id: input.message_id,
    reply: typeof parsed.reply === "string" && parsed.reply.trim()
      ? parsed.reply
      : "This question needs to be confirmed with the administrator. You can ask your mentor during the trial period.",

    country: update.country || null,
    age_passed: boolToTinyInt(update.age_passed),
    english_passed: boolToTinyInt(update.english_passed),
    has_android: boolToTinyInt(update.has_android),
    internet_ok: boolToTinyInt(update.internet_ok),
    hours_ok: boolToTinyInt(update.hours_ok),
    us_time_ok: boolToTinyInt(update.us_time_ok),
    commission_ok: boolToTinyInt(update.commission_ok),
    interested: boolToTinyInt(update.interested),
    screening_step: screeningStep,
    screening_status: screeningStatus,
    rejection_reason: update.rejection_reason || null,

    agent_raw_output: JSON.stringify(parsed),
    parse_error: parseError
  }
}];
